<script lang="ts">
	import AskDock from "$lib/components/AskDock.svelte";
	import Icon from "$lib/components/Icon.svelte";
	import LibraryItemCard from "$lib/components/LibraryItemCard.svelte";
	import { libraryLinks, libraryProvenance, type LibraryItemView, type LibraryKind } from "$lib/data/library";
	let { data } = $props();
	const lib = $derived(data.library);
	let view = $state<"desk"|"graph"|"kanban"|"table">("desk");
	let query = $state("");
	let kind = $state<LibraryKind|null>(null);
	let project = $state<string|null>(null); let scope = $state<string|null>(null); let creator = $state<string|null>(null); let status = $state<string|null>(null);
	let asked = $state(false); let transcript = $state<string|null>(null);
	let selected = $state<LibraryItemView|null>(null);
	let drawer = $state<HTMLDialogElement|null>(null);
	let search = $state<HTMLInputElement|null>(null);
	const results = $derived(lib.items.filter((item) => (!kind || item.kind === kind) && (!project || item.project === project) && (!scope || item.scope === scope) && (!creator || item.creator === creator) && (!status || item.status === status) && `${item.title} ${item.project} ${item.kind} ${item.creator}`.toLowerCase().includes(query.toLowerCase())));
	const graphPositions:Record<string,[number,number]>={"kb-1":[14,22],"kb-2":[14,68],"kb-3":[40,68],"kb-4":[40,12],"kb-5":[64,42],"kb-6":[82,20],"kb-7":[82,70]};
	const graphEdges=$derived(Object.entries(libraryLinks).flatMap(([from,links])=>links.filter(link=>graphPositions[from]&&graphPositions[link.targetId]).map(link=>({from,to:link.targetId,rel:link.rel}))));
	$effect(() => { if (selected && drawer && !drawer.open) drawer.showModal(); });
	function open(item: LibraryItemView){ selected=item; }
	function submit(e:SubmitEvent){e.preventDefault();view="table";}
	function ask(q:string){query=q;asked=true;view="table";transcript=lib.items.some(i=>i.title.toLowerCase().includes(q.toLowerCase().split(" ")[0]||""))?"I found these items in your readable stacks.":"Nothing in the stacks for that. Research egress is not wired.";}
	function keys(e:KeyboardEvent){ if(e.key==="f" && !(e.target instanceof HTMLInputElement)){e.preventDefault();search?.focus();} if(["1","2","3","4"].includes(e.key)&&!(e.target instanceof HTMLInputElement)) view=(["desk","graph","kanban","table"] as const)[Number(e.key)-1]; }
	function graphKey(e:KeyboardEvent){if(!e.key.startsWith("Arrow"))return;const nodes=[...document.querySelectorAll<HTMLButtonElement>(".graph button")];const i=nodes.indexOf(e.currentTarget as HTMLButtonElement);if(i>=0){e.preventDefault();nodes[(i+(e.key==="ArrowLeft"||e.key==="ArrowUp"?-1:1)+nodes.length)%nodes.length]?.focus();}}
</script>
<svelte:window onkeydown={keys}/>
<div class="sign"><h1>The Library</h1><span>Everything anyone here has ever learned. Ask.</span><form onsubmit={submit} title={lib.connected?"Search the stacks":"Store unreachable"}><Icon name="search" size={14}/><input bind:this={search} bind:value={query} placeholder="Search the stacks" aria-label="Search the stacks" disabled={!lib.connected}/></form><div class="seg">{#each ["desk","graph","kanban","table"] as tab}<button class:on={view===tab} onclick={() => view=tab as typeof view} disabled={!lib.connected}>{tab[0].toUpperCase()+tab.slice(1)}</button>{/each}</div><button class="bud" title="Budhole" aria-label="Budhole" disabled={!lib.connected}><Icon name="library" size={16}/></button></div>
{#if !lib.connected}<div class="unavailable"><Icon name="circle-help" size={18}/><div><b>The stacks are not wired yet.</b><p>Rev3 search, item, link, hold, and curation endpoints are Phase 2. Nothing is shown as current.</p></div></div>{/if}
{#if lib.connected}
{#if view==="desk"}
	<section class="ask"><AskDock mode="centered" greeting="Ask the librarian. They know the way, and they know you." onask={ask}/></section>
	<div class="desk"><main><section class="panel"><header><h2>Held for you</h2><span>the librarian set these aside</span></header><div class="two">{#each lib.items.filter(i=>i.hold?.startsWith("Held")).slice(0,2) as item}<LibraryItemCard {item} onopen={open}/>{:else}<p class="empty">Nothing held aside for you yet.</p>{/each}</div><footer><Icon name="scroll-text" size={12}/> kb.search · scope parker · fixture receipt</footer></section><section class="panel"><header><h2>Recommended for you</h2><span>your reading room, not a feed</span></header><div class="two">{#each lib.items.filter(i=>i.hold?.startsWith("Recommended")).slice(0,2) as item}<LibraryItemCard {item} onopen={open}/>{/each}</div><footer><Icon name="scroll-text" size={12}/> librarian picks · reason recommended</footer></section><section class="panel"><header><h2>Relevant to your work now</h2><span>joined to /task/712</span></header>{#each lib.items.slice(4,7) as item}<LibraryItemCard {item} compact onopen={open}/>{/each}<footer><Icon name="scroll-text" size={12}/> lease join · task 712 · fixture</footer></section></main><aside><section class="panel"><header><h2>Recent arrivals</h2><span>your scopes</span></header>{#each lib.items.slice(-3).reverse() as item}<LibraryItemCard {item} compact onopen={open}/>{/each}</section><section class="panel curation"><header><h2>Curation</h2><span>librarian · sweeping</span></header><p>The librarian wants to weed 6 items. Review before anything leaves the stacks.</p><small>weekly sweep · ran 04:00 · 14 in unsorted</small><button disabled={!lib.isMock}>Review 6</button></section><section class="panel"><header><h2>Check before web</h2></header><div class="kpi">87%<small>stacks answered first</small></div><p class="caption">9 web fallbacks this week. All 9 written back.</p></section></aside></div>
{:else if view==="table"}
	<div class="facets"><span>{results.length} results · bm25 + dense · rrf k=60</span><button class:on={kind==="how-to"} onclick={()=>kind=kind==="how-to"?null:"how-to"}>kind: how-to</button><button class:on={project==="fleet"} onclick={()=>project=project==="fleet"?null:"fleet"}>project: fleet</button><button class:on={scope==="fleet-public"} onclick={()=>scope=scope==="fleet-public"?null:"fleet-public"}>scope: fleet-public</button><button class:on={creator==="carson-2"} onclick={()=>creator=creator==="carson-2"?null:"carson-2"}>created-by: carson-2</button><button class:on={status==="verified-shared"} onclick={()=>status=status==="verified-shared"?null:"verified-shared"}>status: verified</button></div><div class="table"><div class="head"><span>title</span><span>project</span><span>updated</span><span>conf</span></div>{#each results as item}<button class="row" onclick={()=>open(item)}><span><b>{item.title}</b><small>{item.kind} · {item.scope} · by {item.creator}</small><em>bm25 “{query||item.kind}” · dense {item.confidence?.toFixed(2)||"—"} · rrf</em></span><code>{item.project}</code><code>{item.updated}</code><code>{item.confidence?.toFixed(2)||"—"}</code></button>{:else}<div class="empty">Nothing in the stacks for that. Research is unavailable until sole egress is wired.</div>{/each}</div>
{:else if view==="kanban"}
	<div class="kanban-note">Status writes are disabled until <code>library.item.update</code> lands. Conflicts will float to the adjudication rail.</div><h2 class="lane-group">Work · task lifecycle</h2><div class="kanban">{#each ["todo","doing","review","done"] as lane}<section><h2>{lane}</h2>{#each lib.items.filter(i=>i.kind==="task"&&i.status===lane) as item}<LibraryItemCard {item} compact onopen={open}/>{:else}<p>All caught up.</p>{/each}</section>{/each}</div><h2 class="lane-group">Knowledge · promotion lifecycle</h2><div class="kanban knowledge">{#each ["draft","verified-shared","superseded","invalidated"] as lane}<section><h2>{lane}</h2>{#each lib.items.filter(i=>i.kind!=="task"&&i.status===lane) as item}<LibraryItemCard {item} compact onopen={open}/>{:else}<p>All caught up.</p>{/each}</section>{/each}</div>
{:else}
	<div class="graph" aria-label="Typed-link dependency graph"><svg viewBox="0 0 100 100" preserveAspectRatio="none" role="img" aria-label="Library item links"><defs><marker id="arrow" markerWidth="3" markerHeight="3" refX="2" refY="1.5" orient="auto"><path d="M0 0L3 1.5L0 3z"/></marker></defs>{#each graphEdges as edge}<line x1={graphPositions[edge.from][0]} y1={graphPositions[edge.from][1]} x2={graphPositions[edge.to][0]} y2={graphPositions[edge.to][1]}><title>{edge.rel}</title></line>{/each}</svg>{#each lib.items.filter(i=>graphPositions[i.id]) as item}<button style={`--x:${graphPositions[item.id][0]}%;--y:${graphPositions[item.id][1]}%`} onclick={()=>open(item)} onkeydown={graphKey}><Icon name={item.kind==="decision"?"milestone":item.kind==="research"?"microscope":"file-text"} size={16}/><span>{item.title}</span></button>{/each}<small>fixture typed links · arrows walk nodes</small></div>
{/if}
{#if asked}<AskDock mode="docked" {transcript} onask={ask}/>{/if}
<dialog bind:this={drawer} onclose={()=>selected=null}>{#if selected}<button class="close" autofocus onclick={()=>drawer?.close()} aria-label="Close item"><Icon name="x" size={16}/></button><header><Icon name="book-open" size={16}/><h2>{selected.title}</h2></header><div class="chips"><span>{selected.kind}</span><span>{selected.status}</span><span><Icon name="shield" size={11}/> semi</span><span>{selected.scope}</span><span>conf {selected.confidence?.toFixed(2)||"—"}</span></div><article>{selected.body}</article><section><h3>Typed links</h3>{#each libraryLinks[selected.id] ?? [] as link}<button class="link" onclick={()=>{const target=lib.items.find(i=>i.id===link.targetId);if(target)selected=target}}><Icon name={link.direction==="out"?"arrow-right":"arrow-left"} size={12}/><code>{link.rel}</code><span>{lib.items.find(i=>i.id===link.targetId)?.title??"target weeded"}</span>{#if link.reason}<small>{link.reason}</small>{/if}</button>{:else}<p>No typed links filed.</p>{/each}</section><section><h3>Provenance</h3><p>created-by-agent:{selected.creator} · responsible-human:{libraryProvenance[selected.id]?.responsibleHuman??"unassigned"} · v{selected.version}</p></section><footer>v{selected.version} · tx_from {libraryProvenance[selected.id]?.txFrom??"unavailable"} · what did we believe when</footer>{/if}</dialog>
{/if}
<style>
	.sign{display:flex;align-items:center;gap:var(--s-3);min-height:40px}.sign h1{font:400 1.0625rem var(--sign)}.sign>span{font:400 .875rem var(--sign);color:var(--jade-text)}.sign form{margin-inline-start:auto;width:320px;min-height:32px;display:flex;align-items:center;gap:var(--s-2);padding:0 var(--s-2);background:var(--s2);border-radius:var(--r-sm)}input{border:0;outline:0;background:none;color:var(--text);width:100%;font-size:.75rem}.sign form:focus-within{box-shadow:0 0 0 2px var(--petal)}.seg{display:flex;background:var(--s2);border-radius:var(--r-sm);padding:2px}.seg button,.bud{border:0;background:none;color:var(--text-2);min-height:32px;padding:0 var(--s-2);border-radius:6px;text-transform:capitalize}.seg button.on{background:var(--petal-soft);color:var(--petal-text)}.bud{width:32px;padding:0}.unavailable{display:flex;gap:var(--s-2);background:var(--warn-soft);color:var(--warn-text);padding:var(--s-3);margin-top:var(--s-3);border-radius:var(--r-xs)}.unavailable p{font-size:.75rem;color:var(--text-2)}.ask{margin:var(--s-4) 0}.desk{display:grid;grid-template-columns:minmax(0,1fr) 344px;gap:var(--s-3);padding-bottom:var(--s-4)}.desk main,.desk aside{display:flex;flex-direction:column;gap:var(--s-3)}.panel{background:var(--s1);border-radius:var(--r-md);padding:var(--s-3)}.panel header{display:flex;align-items:baseline;gap:var(--s-2);margin-bottom:var(--s-2)}.panel h2{font-size:.84375rem}.panel header span{font-size:.6875rem;color:var(--text-3)}.panel footer{display:flex;align-items:center;gap:var(--s-2);border-top:1px solid var(--rule);padding-top:var(--s-2);margin-top:var(--s-2);font:400 .6875rem var(--mono);color:var(--text-3)}.two{display:grid;grid-template-columns:1fr 1fr;gap:var(--s-2)}.empty{padding:var(--s-3);font-size:.8125rem;color:var(--text-3)}.curation p{font-size:.8125rem;color:var(--text-2)}.curation small{display:block;color:var(--text-3);margin:var(--s-2) 0}.curation button{border:0;background:var(--s2);border-radius:var(--r-sm);min-height:32px;padding:0 var(--s-3)}.kpi{font:500 1.75rem var(--mono)}.kpi small{display:block;font:400 .75rem var(--sans);color:var(--text-3)}.caption{font-size:.75rem;color:var(--text-3)}.facets{display:flex;align-items:center;gap:var(--s-2);margin:var(--s-3) 0}.facets>span{margin-inline-end:auto;font:400 .6875rem var(--mono);color:var(--text-3)}.facets button{border:0;background:var(--s2);border-radius:var(--r-pill);min-height:24px;color:var(--text-2)}.facets button.on{background:var(--petal-soft);color:var(--petal-text)}.table{background:var(--s1);border-radius:var(--r-xs)}.head,.row{display:grid;grid-template-columns:1fr 120px 80px 64px;gap:var(--s-2);align-items:center}.head{min-height:32px;padding:0 var(--s-3);font:500 .6875rem var(--mono);color:var(--text-3)}.row{width:100%;border:0;border-top:1px solid var(--rule);background:none;color:var(--text);text-align:left;min-height:64px;padding:var(--s-1) var(--s-3)}.row:hover{background:var(--s2)}.row b,.row small,.row em{display:block}.row b{font-size:.8125rem}.row small,.row em{font:400 .6875rem var(--mono);color:var(--text-3)}.row em{color:var(--jade-text);margin-top:2px}.row code{text-align:right}.kanban{display:grid;grid-template-columns:repeat(4,1fr);gap:var(--s-3);margin-top:var(--s-3)}.kanban section{background:var(--s2);padding:var(--s-2);border-radius:var(--r-xs)}.kanban h2{font:500 .6875rem var(--mono);text-transform:uppercase;color:var(--text-3)}.kanban p{font-size:.75rem;color:var(--text-3);padding:var(--s-2)}.graph{height:480px;background:var(--s1);position:relative;margin-top:var(--s-3);border-radius:var(--r-xs)}.graph svg{position:absolute;inset:0;width:100%;height:100%}.graph path{fill:none;stroke:var(--text-3);stroke-width:1;marker-end:url(#arrow)}.graph button{position:absolute;left:var(--x);top:var(--y);width:140px;border:0;background:var(--s2);color:var(--text);border-radius:var(--r-xs);padding:var(--s-2)}.graph button span{display:block;font:400 .6875rem var(--mono);margin-top:var(--s-1)}dialog{width:420px;max-width:calc(100% - 32px);height:100%;max-height:none;margin:0 0 0 auto;border:0;background:var(--s1);color:var(--text);padding:var(--s-4);box-shadow:var(--shadow-pop)}dialog::backdrop{background:rgba(12,10,8,.24)}dialog .close{position:absolute;right:var(--s-3);top:var(--s-3);border:0;background:none;color:var(--text)}dialog header{display:flex;gap:var(--s-2);padding-right:var(--s-4)}dialog header h2{font:400 1.0625rem var(--sign)}.chips{display:flex;gap:var(--s-1);flex-wrap:wrap;margin:var(--s-3) 0}.chips span{display:flex;align-items:center;gap:3px;background:var(--s2);border-radius:var(--r-pill);padding:2px var(--s-2);font:400 .6875rem var(--mono)}dialog article{line-height:1.6;color:var(--text-2);margin:var(--s-4) 0}dialog section{border-top:1px solid var(--rule);padding:var(--s-3) 0}dialog h3{font:500 .6875rem var(--mono);text-transform:uppercase;color:var(--text-3)}dialog section p,dialog footer{display:flex;align-items:center;gap:var(--s-2);font:400 .6875rem var(--mono);color:var(--text-3);margin-top:var(--s-2)}
	.facets button{min-height:32px;padding:0 var(--s-2)}.kanban{margin-top:var(--s-2)}.kanban-note{font-size:.75rem;color:var(--text-3);background:var(--s2);padding:var(--s-2);margin-top:var(--s-3);border-radius:var(--r-xs)}.lane-group{font:500 .6875rem var(--mono);text-transform:uppercase;color:var(--text-3);margin-top:var(--s-3)}.graph path{fill:var(--text-3)}.graph line{stroke:var(--text-3);stroke-width:.4;marker-end:url(#arrow)}.graph>small{position:absolute;left:var(--s-2);bottom:var(--s-2);font:400 .6875rem var(--mono);color:var(--text-3)}.graph button{min-height:48px;transform:translate(-50%,-50%)}dialog .close{width:32px;height:32px}.link{width:100%;min-height:40px;border:0;background:transparent;color:var(--text-2);display:grid;grid-template-columns:16px 90px 1fr;gap:var(--s-2);align-items:center;text-align:left;border-radius:var(--r-xs)}.link:hover{background:var(--s2)}.link small{grid-column:3;color:var(--text-3)}
	@media(max-width:900px){.sign>span,.bud{display:none}.sign form{width:220px}.desk{grid-template-columns:1fr}.kanban{grid-template-columns:1fr 1fr}}@media(max-width:767px){.sign{flex-wrap:wrap}.sign form{order:3;width:100%}.seg{display:none}.desk aside,.desk main .panel:not(:first-child){display:none}.two{grid-template-columns:1fr}.head,.row{grid-template-columns:1fr 56px}.head span:nth-child(2),.head span:nth-child(4),.row>code:nth-of-type(1),.row>code:nth-of-type(3){display:none}.kanban{grid-template-columns:1fr}.graph{display:none}}
</style>
